const items = $input.all();
const rawData = items.map(item => item.json);

// 1. Tabela de Preços
const precos = {
  "Google Workspace Frontline Starter": 30.00,
  "Google Workspace Business Starter": 41.00,
  "Google Workspace Business Plus": 81.80,
  "SEM LICENÇA": 0
};

// Função de limpeza padrão ultra segura
const limpar = (t) => {
  if (!t) return "";
  return t
    .toString()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
};

// 2. Unificação de Dados
const masterMap = {};

rawData.forEach(item => {
  const emailBruto = item.userId || item["E-MAIL/USUARIO"];
  const email = limpar(emailBruto);

  if (!email || email === "sem e-mail") return;

  if (!masterMap[email]) {
    masterMap[email] = {
      email,
      nome: null,
      cargo: null,
      empresa: null,
      site: null,
      skuName: null,
      orgUnitPath: null,
      orgUnitPathClean: null
    };
  }

  if (item.NOME) masterMap[email].nome = item.NOME;
  if (item.CARGO) masterMap[email].cargo = item.CARGO;
  if (item.EMPRESA) masterMap[email].empresa = item.EMPRESA;
  if (item.SITE) masterMap[email].site = item.SITE;
  if (item.skuName) masterMap[email].skuName = item.skuName;

  if (item.orgUnitPath) {
    masterMap[email].orgUnitPath = item.orgUnitPath;
    masterMap[email].orgUnitPathClean = limpar(item.orgUnitPath);
  }
});

// 3. Identificação de Departamento
const identificarDepto = (m) => {
  const p = m.orgUnitPathClean || "";
  const c = limpar(m.cargo);
  const e = m.email || "";

  if (
    e === "suporte@acgconsultoria.com.br" ||
    p.includes("precatorio") ||
    c.includes("precatorio")
  ) return "PRECATORIO";

  if (p.includes("marketing") || c.includes("marketing"))
    return "MARKETING";

  if (
    p.includes("tecnologia") ||
    p.includes("data science") ||
    p.includes("ti") ||
    c.includes("ti")
  ) return "TI";

  if (p.includes("financeiro") || c.includes("financeiro"))
    return "FINANCEIRO";

  if (
    p.includes("recursos humanos") ||
    p.includes("treinamento") ||
    c.includes("rh")
  ) return "RH / ADM";

  if (p.includes("backoffice") || p.includes("bko"))
    return "OPERACIONAL";

  if (
    p.includes("vendas") ||
    p.includes("consignado") ||
    p.includes("coordenador") ||
    p.includes("gerente") ||
    p.includes("lider comercial") ||
    p.includes("assistente comercial") ||
    p.includes("diretoria") ||
    c.includes("vendas") ||
    c.includes("coordenador") ||
    c.includes("gerente")
  ) return "COMERCIAL / VENDAS";

  // Fallback seguro
  if (m.orgUnitPath) {
    const partes = m.orgUnitPath
      .split("/")
      .map(p => p.trim())
      .filter(p => p.length > 0);

    if (partes.length > 0) {
      return partes[partes.length - 1].toUpperCase();
    }
  }

  return "OUTROS";
};

// 4. Identificação de Empresa / Rateio
const identificarEmpresaRateio = (m, depto) => {
  const email = m.email || "";
  const dominio = email.includes("@") ? email.split("@")[1] : "";
  const site = limpar(m.site);
  const empOrig = limpar(m.empresa);

  if (dominio.includes("niu") || empOrig.includes("niu"))
    return "NIU";

  if (depto === "PRECATORIO")
    return "A.C.G. PRECATORIO";

  const isComercial = depto === "COMERCIAL / VENDAS";

  if (isComercial) {
    if (site.includes("cosmopolis"))
      return "GASPAR ASSESSORIA EMPRESARIAL LTDA";

    if (site.includes("paulinia"))
      return "MDG INTERMEDIACOES DE NEGOCIOS EIRELI";

    if (dominio.includes("acgconsultoria"))
      return "A.C.G. CONSULTORIA EM GESTAO EMPRESARIAL LTDA";

    return "MDG INTERMEDIACOES DE NEGOCIOS EIRELI";
  }

  const setoresApoio = ["TI", "FINANCEIRO", "RH / ADM", "OPERACIONAL", "MARKETING"];
  if (setoresApoio.includes(depto))
    return "RATEIO";

  return "RATEIO";
};

// 5. Mapeamento Final
return Object.values(masterMap).map(m => {

  const depto = identificarDepto(m);
  const empresa = identificarEmpresaRateio(m, depto);

  const nomeSeguro = m.nome
    ? m.nome
    : (m.email && m.email.includes("@")
        ? m.email.split("@")[0].toUpperCase()
        : "SEM NOME");

  const valor = precos[m.skuName] ?? 0;

  return {
    json: {
      nome: nomeSeguro,
      empresa_rateio: empresa,
      departamento_rateio: depto,
      email: m.email,
      valor_estimado: valor,
      sku: m.skuName || "SEM LICENÇA",
      path: m.orgUnitPath || "N/A",
      site: m.site || "N/A"
    }
  };
});

const items = $input.all();
const resumo = {};

// 1. Agrupar e Somar os valores conforme as regras processadas no nó anterior
for (const item of items) {
  const d = item.json;

  // Consideramos apenas licenças que geram custo (valor > 0)
  if (d.valor_estimado && d.valor_estimado > 0) {
    const empresa = d.empresa_rateio || "OUTROS";
    const depto = d.departamento_rateio || "DIVERSOS";
    const valor = d.valor_estimado;

    // Criamos uma chave única combinando Empresa e Setor
    const chave = `${empresa} | ${depto}`;

    if (!resumo[chave]) {
      resumo[chave] = {
        empresa: empresa,
        departamento: depto,
        valor_total: 0,
        quantidade_licencas: 0
      };
    }

    resumo[chave].valor_total += valor;
    resumo[chave].quantidade_licencas += 1;
  }
}

// 2. Converter o objeto de agrupamento em uma lista para o n8n
const resultadoFinal = Object.values(resumo).map(r => {
  return {
    json: {
      empresa: r.empresa,
      departamento: r.departamento,
      valor_total: parseFloat(r.valor_total.toFixed(2)), // Formata para 2 casas decimais
      quantidade_licencas: r.quantidade_licencas
    }
  };
});

// 3. Ordenar por Empresa para facilitar a leitura no relatório
return resultadoFinal.sort((a, b) => 
  a.json.empresa.localeCompare(b.json.empresa) || 
  a.json.departamento.localeCompare(b.json.departamento)
);

// Pega a lista de usuários que o Google retornou
const usuarios = $input.first().json.users || [];

// Conta quantos usuários existem (Licenças em uso)
const licencasEmUso = usuarios.length;

// Define o total de licenças que você paga no contrato
const totalLicencas = 150; 

// Calcula as licenças disponíveis
const licencasLivres = totalLicencas - licencasEmUso;

// Retorna o resultado limpo e organizado para o n8n
return {
  total_contratado: totalLicencas,
  licencas_em_uso: licencasEmUso,
  licencas_livres: licencasLivres
};

